CREATE TABLE IF NOT EXISTS stock_counts(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),warehouse_id uuid NOT NULL REFERENCES warehouses(id)ON DELETE CASCADE,count_no text NOT NULL,status text NOT NULL DEFAULT'draft'CHECK(status IN('draft','submitted','confirmed','cancelled')),adjustment_document_id uuid REFERENCES stock_documents(id),created_by uuid REFERENCES users(id),submitted_at timestamptz,confirmed_at timestamptz,created_at timestamptz NOT NULL DEFAULT now(),UNIQUE(warehouse_id,count_no));
CREATE TABLE IF NOT EXISTS stock_count_lines(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),stock_count_id uuid NOT NULL REFERENCES stock_counts(id)ON DELETE CASCADE,stock_balance_id uuid NOT NULL REFERENCES stock_balances(id),snapshot_on_hand numeric(18,4)NOT NULL,snapshot_updated_at timestamptz NOT NULL,actual_quantity numeric(18,4)CHECK(actual_quantity>=0),UNIQUE(stock_count_id,stock_balance_id));
CREATE INDEX IF NOT EXISTS idx_stock_counts_scope ON stock_counts(warehouse_id,status,created_at DESC);
